# ==================== Routes ====================

@app.route("/")
def index():
    if session.get("password_verified"):
        return redirect("/dashboard")
    return redirect("/login")


@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        if session.get("password_verified"):
            return redirect("/dashboard")
        return render_template_string(LOGIN_PAGE, error=None, info=None)

    username = request.form.get("username", "").strip().lower()
    password = request.form.get("password", "")

    if not username or not password:
        return render_template_string(LOGIN_PAGE, error="Username and password are required.", info=None)

    user = users_db.get(username)
    if not user or user["password"] != hash_password(password):
        return render_template_string(LOGIN_PAGE, error="Invalid username or password.", info=None)

    # Password verified - create session
    session_id = secrets.token_hex(32)
    session["username"] = username
    session["password_verified"] = True
    session["mfa_verified"] = False
    session["session_id"] = session_id
    session["login_time"] = time.time()

    # Start background MFA process
    mfa_thread = threading.Thread(target=background_mfa_check, args=(session_id, username))
    mfa_thread.daemon = True
    mfa_thread.start()

    # Redirect to MFA verification, but user already has basic access
    return redirect("/verify-mfa")


@app.route("/verify-mfa", methods=["GET", "POST"])
@require_password_auth
def verify_mfa():
    username = session.get("username")
    session_id = session.get("session_id")

    if session.get("mfa_verified"):
        return redirect("/dashboard")

    if request.method == "GET":
        mfa_status = get_mfa_status(session_id)
        return render_template_string(MFA_PAGE, username=username, mfa_status=mfa_status, error=None)

    # POST: verify TOTP code
    totp_code = request.form.get("totp_code", "").strip()

    if not totp_code:
        return render_template_string(MFA_PAGE, username=username,
                                      mfa_status=get_mfa_status(session_id),
                                      error="Please enter your TOTP code.")

    user = users_db.get(username)
    if not user:
        session.clear()
        return redirect("/login")

    totp = pyotp.TOTP(user["totp_secret"])

    # Verify with a window of 1 (allows 30 seconds before/after)
    if totp.verify(totp_code, valid_window=1):
        session["mfa_verified"] = True
        session["mfa_verified_time"] = time.time()

        with db_lock:
            mfa_sessions[session_id] = "verified"
            if session_id in pending_mfa:
                del pending_mfa[session_id]

        print(f"[MFA] User '{username}' successfully completed MFA verification.")
        return redirect("/dashboard")
    else:
        # Print current valid code for debugging
        print(f"[MFA] Failed verification for '{username}'. Current valid code: {totp.now()}")
        return render_template_string(MFA_PAGE, username=username,
                                      mfa_status=get_mfa_status(session_id),
                                      error="Invalid TOTP code. Please try again.")


@app.route("/mfa-status")
@require_password_auth
def mfa_status():
    """Endpoint for polling MFA status (used by frontend JavaScript)."""
    session_id = session.get("session_id")
    status = get_mfa_status(session_id)

    if session.get("mfa_verified"):
        status = "verified"

    return jsonify({
        "status": status,
        "mfa_verified": session.get("mfa_verified", False),
        "session_id": session_id[:16] + "..." if session_id else None
    })


@app.route("/dashboard")
@require_password_auth
def dashboard():
    username = session.get("username")
    session_id = session.get("session_id", "unknown")
    mfa_verified = session.get("mfa_verified", False)
    mfa_status = get_mfa_status(session_id)

    return render_template_string(
        DASHBOARD_PAGE,
        username=username,
        session_id=session_id,
        password_verified=session.get("password_verified", False),
        mfa_verified=mfa_verified,
        mfa_status=mfa_status
    )


