@app.route("/logout")
def logout():
    session_id = session.get("session_id")
    username = session.get("username", "unknown")

    # Clean up MFA tracking
    with db_lock:
        if session_id in mfa_sessions:
            del mfa_sessions[session_id]
        if session_id in pending_mfa:
            del pending_mfa[session_id]

    session.clear()
    print(f"[Logout] User '{username}' logged out.")
    return redirect("/login")


# ==================== Background MFA Cleanup ====================

def cleanup_expired_mfa():
    """Periodically clean up expired MFA sessions."""
    while True:
        time.sleep(60)  # Run every minute
        current_time = time.time()
        with db_lock:
            expired = [
                sid for sid, data in pending_mfa.items()
                if current_time > data.get("expires_at", 0)
            ]
            for sid in expired:
                print(f"[Cleanup] Expired MFA session: {sid[:16]}...")
                del pending_mfa[sid]
                if sid in mfa_sessions:
                    mfa_sessions[sid] = "expired"


# ==================== Error Handlers ====================

@app.errorhandler(401)
def unauthorized(e):
    return jsonify({"error": "Unauthorized", "redirect": "/login"}), 401


@app.errorhandler(403)
def forbidden(e):
    return jsonify({"error": "Forbidden - MFA required", "redirect": "/verify-mfa"}), 403


@app.errorhandler(404)
def not_found(e):
    return jsonify({"error": "Not found"}), 404


